                <span className="text-zinc-300 truncate w-40" title={hotspot.label}>
                  {hotspot.label}
                </span>
                <span className="text-zinc-500 text-xs px-2 py-1 bg-zinc-800 rounded">
                  {hotspot.connections} conn
                </span>
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}

'use client';

import React, { useCallback, useEffect } from 'react';
import {
  ReactFlow,
  Controls,
  Background,
  useNodesState,
  useEdgesState,
  Node as RFNode,
  Edge as RFEdge,
  ReactFlowProvider,
  useReactFlow,
  BackgroundVariant,
  MarkerType,
} from '@xyflow/react';
import '@xyflow/react/dist/style.css';
import { useDispatch, useSelector } from 'react-redux';
import { RootState } from '@/store';
import { setSelectedNodeId, clearSelection, expandNodes } from '@/store/graphSlice';
import { FileNode, ClassNode, FunctionNode, DefaultNode, DirectoryNode } from './nodes/CustomNodes';
import { computeElkLayout } from '@/lib/elk-layout';

const nodeTypes = {
  custom: DefaultNode,
  Directory: DirectoryNode,
  File: FileNode,
  Class: ClassNode,
  Function: FunctionNode,
};

interface GraphCanvasProps {
  initialNodes: RFNode[];
  initialEdges: RFEdge[];
}

function FlowCanvas({ initialNodes, initialEdges }: GraphCanvasProps) {
  const [nodes, setNodes, onNodesChange] = useNodesState<RFNode>([]);
  const [edges, setEdges, onEdgesChange] = useEdgesState<RFEdge>([]);

  const dispatch = useDispatch();
  const { fitView } = useReactFlow();

  const expandedNodeIds = useSelector((state: RootState) => state.graph.expandedNodeIds);
  const selectedNodeId = useSelector((state: RootState) => state.graph.selectedNodeId);
  const highlightedNodeIds = useSelector((state: RootState) => state.graph.highlightedNodeIds);
  const searchQuery = useSelector((state: RootState) => state.graph.searchQuery);

  useEffect(() => {
    const computeLayout = async () => {
      // ─────────────────────────────────────────────
      // 1. Decide which nodes are visible
      //    Root nodes (no parentId) are always visible.
      //    A child becomes visible when its direct parent is both
      //    visible AND listed in expandedNodeIds.
      // ─────────────────────────────────────────────
      const expandedSet = new Set<string>(expandedNodeIds);
      const visibleIds = new Set<string>(
        initialNodes.filter(n => !n.data.parentId).map(n => n.id)
      );

      let changed = true;
      while (changed) {
        changed = false;
        initialNodes.forEach(n => {
          const pid = n.data.parentId as string | undefined;
          if (!visibleIds.has(n.id) && pid && visibleIds.has(pid) && expandedSet.has(pid)) {
            visibleIds.add(n.id);
            changed = true;
          }
        });
      }

      // ─────────────────────────────────────────────
      // 2. Build the visible node list
      // ─────────────────────────────────────────────
      const visibleNodes: RFNode[] = initialNodes
        .filter(n => visibleIds.has(n.id))
        .map(n => ({
          ...n,
          type: (n.data.type as string) in nodeTypes ? (n.data.type as string) : 'custom',
        }));

      // ─────────────────────────────────────────────
      // 3. Build semantic (non-hierarchy) edges with edge-lifting.
      //    Hierarchy edges (Directory→File→Class→Function) are generated
      //    automatically inside computeElkLayout from parentId, so we
      //    only supply the "data relationship" edges here.
      // ─────────────────────────────────────────────
      const getVisibleAncestor = (id: string): string | null => {
        let cur: string | undefined = id;
        while (cur) {
          if (visibleIds.has(cur)) return cur;
          const n = initialNodes.find(n => n.id === cur);
          cur = n?.data.parentId as string | undefined;
        }
        return null;
      };

      const semanticEdgesMap = new Map<string, RFEdge>();

      initialEdges.forEach(e => {
        const rawType = (e.data?.originalData as any)?.type as string;
        // Skip structural edges — they are already covered by parentId hierarchy
        if (rawType === 'DEFINES' || rawType === 'CONTAINS') return;

        const src = getVisibleAncestor(e.source);
        const tgt = getVisibleAncestor(e.target);
        if (!src || !tgt || src === tgt) return;

        const key = `sem::${src}→${tgt}`;
        if (semanticEdgesMap.has(key)) return;

        semanticEdgesMap.set(key, {
          id: key,
          source: src,
          target: tgt,
          type: 'default',
          animated: true,
          markerEnd: { type: MarkerType.ArrowClosed, color: '#60a5fa', width: 14, height: 14 },
          style: { stroke: '#60a5fa', strokeWidth: 2, opacity: 0.75 },
          label: rawType,
          labelStyle: { fill: '#93c5fd', fontSize: 10 },
          labelBgStyle: { fill: 'transparent' },
        });
      });

      const semanticEdges = Array.from(semanticEdgesMap.values());

      // ─────────────────────────────────────────────
      // 4. Run ELK layout.
      //    computeElkLayout will inject hierarchy edges (amber dashed for
      //    Directory→*, blue dashed for File→Class/Function) from parentId,
      //    then layout all nodes with generous spacing.
      // ─────────────────────────────────────────────
      const { nodes: laid, edges: laidEdges } = await computeElkLayout(visibleNodes, semanticEdges);

      setNodes(laid);
      setEdges(laidEdges);

      // Fit the view after a short paint delay
      setTimeout(() => fitView({ padding: 0.18, duration: 700 }), 80);
    };

    computeLayout();
  }, [initialNodes, initialEdges, expandedNodeIds, setNodes, setEdges, fitView]);

  // ─────────────────────────────────────────────
  // Highlight / search opacity effects
  // ─────────────────────────────────────────────
  useEffect(() => {
    // Auto-expand parents of highlighted nodes so they become visible
    if (highlightedNodeIds.length > 0) {
      const parentsToExpand = new Set<string>();
      highlightedNodeIds.forEach(id => {
        let cur = initialNodes.find(n => n.id === id)?.data?.parentId as string | undefined;
        while (cur) {
          parentsToExpand.add(cur);
          cur = initialNodes.find(n => n.id === cur)?.data?.parentId as string | undefined;
        }
      });
      if (parentsToExpand.size > 0) {
        dispatch(expandNodes(Array.from(parentsToExpand)));
      }
    }

    setNodes(nds =>
      nds.map(node => {
        const isSelected = node.id === selectedNodeId;
        const isHighlighted = highlightedNodeIds.length > 0
          ? highlightedNodeIds.includes(node.id)
          : false;

        let opacity = 1;
        if (highlightedNodeIds.length > 0 && !isHighlighted && !isSelected) opacity = 0.2;
        if (searchQuery && !(node.data?.label as string || '').toLowerCase().includes(searchQuery.toLowerCase())) opacity = 0.1;

        return {
          ...node,
          selected: isSelected,
          style: { ...node.style, opacity, transition: 'opacity 0.3s ease' },
        };
      })
    );

    setEdges(eds =>
      eds.map(edge => {
        // Keep hierarchy edges (amber/blue dashes) always at full opacity
        const isHierarchy = edge.id.startsWith('hier::');
        let opacity = isHierarchy ? 0.6 : 1;
        if (!isHierarchy && highlightedNodeIds.length > 0) {
          const hit = highlightedNodeIds.includes(edge.source) || highlightedNodeIds.includes(edge.target);
          if (!hit) opacity = 0.1;
        }
        return { ...edge, style: { ...edge.style, opacity, transition: 'opacity 0.3s ease' } };
      })
    );
  }, [selectedNodeId, highlightedNodeIds, searchQuery, setNodes, setEdges]);

  const onNodeClick = useCallback((_event: React.MouseEvent, node: RFNode) => {
    dispatch(setSelectedNodeId(node.id));
  }, [dispatch]);

  const onPaneClick = useCallback(() => {
    dispatch(clearSelection());
  }, [dispatch]);

  return (
    <ReactFlow
      nodes={nodes}
      edges={edges}
      onNodesChange={onNodesChange}
      onEdgesChange={onEdgesChange}
      onNodeClick={onNodeClick}
      onPaneClick={onPaneClick}
      nodeTypes={nodeTypes}
      fitView
      className="bg-zinc-950"
      minZoom={0.03}
      maxZoom={2}
    >
      <Background color="#27272a" variant={BackgroundVariant.Dots} gap={20} size={1} />
      <Controls className="bg-zinc-900 border-zinc-800 fill-zinc-400" />
    </ReactFlow>
  );
}

export function GraphCanvas(props: GraphCanvasProps) {
  return (
    <ReactFlowProvider>
      <FlowCanvas {...props} />
    </ReactFlowProvider>
  );
}

'use client';

import React from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { RootState } from '@/store';
import { useGetImpactQuery, useGetNodesQuery } from '@/store/api/aiekpApi';
import { setSelectedNodeId, setHighlightedNodeIds } from '@/store/graphSlice';
import { Node as RFNode } from '@xyflow/react';
import { AffectedNode } from '@/lib/api-types';
import { Layers, FileCode, SearchCode, Folder } from 'lucide-react';

export function NodeDetailPanel({ nodes }: { nodes: RFNode[] }) {
  const dispatch = useDispatch();
  const selectedNodeId = useSelector((state: RootState) => state.graph.selectedNodeId);
  const highlightedNodeIds = useSelector((state: RootState) => state.graph.highlightedNodeIds);

  const { data: impactData, isLoading: isLoadingImpact, refetch } = useGetImpactQuery(selectedNodeId as string, {
    skip: !selectedNodeId,
  });
  const { isLoading: isLoadingNodes } = useGetNodesQuery();

  if (!selectedNodeId) {
    if (isLoadingNodes) {
      return (
        <div className="w-96 bg-zinc-900 border-l border-zinc-800 h-full overflow-y-auto flex flex-col shadow-xl z-20">
          <div className="p-4 border-b border-zinc-800 bg-zinc-950/50">
            <div className="h-6 w-3/4 bg-zinc-800 rounded animate-pulse mb-2"></div>
            <div className="h-4 w-1/4 bg-zinc-800 rounded animate-pulse"></div>
          </div>
          <div className="p-4 border-b border-zinc-800 space-y-3">
            <div className="h-4 w-1/3 bg-zinc-800 rounded animate-pulse"></div>
            <div className="h-10 w-full bg-zinc-800 rounded animate-pulse"></div>
          </div>
          <div className="p-4 space-y-4 flex-1">
            <div className="h-4 w-1/4 bg-zinc-800 rounded animate-pulse mb-4"></div>
            <div className="space-y-3">
              {[1, 2, 3].map(i => (
                <div key={i}>
                  <div className="h-3 w-1/4 bg-zinc-800 rounded animate-pulse mb-1"></div>
                  <div className="h-4 w-full bg-zinc-800 rounded animate-pulse"></div>
                </div>
              ))}
            </div>
          </div>
        </div>
      );
    }
    return null;
  }

  const selectedNode = nodes.find(n => n.id === selectedNodeId);
  const originalData = selectedNode?.data?.originalData as any;
  const nodeLabel = selectedNode?.data?.label as string;

  const handleAnalyzeImpact = () => {
    if (impactData?.affected) {
      dispatch(setHighlightedNodeIds(impactData.affected.map((n) => n.id)));
    } else {
      refetch().then((res) => {
        if (res.data?.affected) {
          dispatch(setHighlightedNodeIds(res.data.affected.map((n) => n.id)));
        }
      });
    }
  };

  const handleClearImpact = () => {
    dispatch(setHighlightedNodeIds([]));
  };

  const handleExportMarkdown = () => {
    if (!impactData || !impactData.affected.length) return;

    let mdContent = `# Impact Analysis for ${impactData.source_node.label}\n\n`;
    mdContent += `**Type**: ${impactData.source_node.type}\n`;
    mdContent += `**ID**: \`${impactData.source_node.id}\`\n\n`;

    const maxDepth = Math.max(...impactData.affected.map(n => n.depth));
    for (let d = 1; d <= maxDepth; d++) {
      const nodesAtDepth = impactData.affected.filter(n => n.depth === d);
      if (nodesAtDepth.length > 0) {
        mdContent += `## Depth ${d} (${d === 1 ? 'Direct' : 'Indirect'})\n\n`;
        nodesAtDepth.forEach(n => {
          mdContent += `- **${n.label}** (\`${n.type}\`) via _${n.via_relation}_\n`;
        });
        mdContent += '\n';
      }
    }

    const blob = new Blob([mdContent], { type: 'text/markdown' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `impact-analysis-${nodeLabel || 'node'}.md`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const getNodeIcon = (type: string) => {
    switch (type) {
      case 'File': return <FileCode size={14} className="text-blue-400" />;
      case 'Class': return <Layers size={14} className="text-purple-400" />;
      case 'Function': return <SearchCode size={14} className="text-emerald-400" />;
      default: return <Folder size={14} className="text-amber-400" />;
    }
  };

  // Group affected nodes by depth
  const affectedByDepth = impactData?.affected ? impactData.affected.reduce((acc, node) => {
    if (!acc[node.depth]) acc[node.depth] = [];
    acc[node.depth].push(node);
    return acc;
  }, {} as Record<number, AffectedNode[]>) : {};

  return (
    <div className="w-96 bg-zinc-900 border-l border-zinc-800 h-full overflow-y-auto flex flex-col shadow-xl z-20">
      <div className="p-4 border-b border-zinc-800 bg-zinc-950/50">
        <h2 className="text-lg font-semibold text-white break-all">
          {nodeLabel || selectedNodeId}
        </h2>
        <div className="mt-1 flex items-center gap-2">
          <span className="inline-flex items-center rounded-full bg-zinc-800 px-2 py-1 text-xs font-medium text-zinc-300">
            {originalData?.type || 'Unknown'}
          </span>
        </div>
      </div>

      <div className="p-4 border-b border-zinc-800">
        <h3 className="text-sm font-medium text-zinc-400 uppercase tracking-wider mb-3">Actions</h3>

        {originalData?.type === 'Directory' ? (
          <div className="text-sm text-zinc-500 italic text-center p-2 bg-zinc-950/50 rounded-md border border-zinc-800">
            Impact analysis is not available for directory nodes.
          </div>
        ) : (
          <>
            {highlightedNodeIds.length > 0 ? (
              <button
                onClick={handleClearImpact}
                className="w-full flex justify-center py-2 px-4 border border-zinc-700 rounded-md shadow-sm text-sm font-medium text-white bg-zinc-800 hover:bg-zinc-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-zinc-500"
              >
                Clear Impact Analysis
              </button>
            ) : (
              <button
                onClick={handleAnalyzeImpact}
                disabled={isLoadingImpact || (impactData && impactData.affected.length === 0)}
                className="w-full flex justify-center py-2 px-4 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 disabled:opacity-50 disabled:bg-zinc-700 disabled:text-zinc-400"
              >
                {isLoadingImpact 
                  ? 'Analyzing...' 
                  : (impactData && impactData.affected.length === 0 
                      ? 'No Impact Found' 
                      : 'Analyze Impact')}
              </button>
            )}

            {/* Remove the redundant text below since it's now on the disabled button */}
          </>
        )}
      </div>

      {highlightedNodeIds.length > 0 && impactData?.affected && impactData.affected.length > 0 && (
        <div className="p-4 border-b border-zinc-800">
          <div className="flex justify-between items-center mb-3">
            <h3 className="text-sm font-medium text-zinc-400 uppercase tracking-wider">Affected Nodes</h3>
            <button 
              onClick={handleExportMarkdown}
              className="text-xs text-blue-400 hover:text-blue-300"
            >
              Export .md
            </button>
          </div>
          <div className="space-y-4">
            {Object.entries(affectedByDepth).map(([depth, nodes]) => (
              <div key={depth}>
                <h4 className="text-xs font-semibold text-zinc-500 mb-2">
                  Depth {depth} {Number(depth) === 1 ? '(Direct)' : '(Indirect)'}
                </h4>
                <ul className="space-y-2">
                  {nodes.map(node => (
                    <li 
                      key={node.id}
                      className="flex flex-col gap-1 p-2 rounded bg-zinc-950/50 hover:bg-zinc-800/80 cursor-pointer border border-zinc-800/50"
                      onClick={() => dispatch(setSelectedNodeId(node.id))}
                    >
                      <div className="flex items-center gap-2">
                        {getNodeIcon(node.type)}
                        <span className="text-sm font-medium text-zinc-200 truncate" title={node.label}>{node.label}</span>
                      </div>
                      <div className="flex justify-between items-center pl-6">
                        <span className="text-xs text-zinc-500">{node.type}</span>
                        <span className="text-[10px] bg-zinc-800 px-1.5 py-0.5 rounded text-zinc-400 font-mono">
                          via {node.via_relation}
                        </span>
                      </div>
                    </li>
                  ))}
                </ul>
              </div>
            ))}
          </div>
        </div>
      )}

      <div className="p-4 flex-1">
        <h3 className="text-sm font-medium text-zinc-400 uppercase tracking-wider mb-3">Properties</h3>
        <dl className="space-y-3">
          {originalData?.properties && Object.entries(originalData.properties).map(([key, value]) => (
            <div key={key} className="break-all">
              <dt className="text-xs text-zinc-500">{key}</dt>
              <dd className="text-sm text-zinc-200 mt-1">
                {typeof value === 'object' ? JSON.stringify(value) : String(value)}
              </dd>
            </div>
          ))}
        </dl>
      </div>
    </div>
  );
}

